args.sparql:
SELECT ?award ?label WHERE {
  ?award wdt:P31/wdt:P279* wd:Q618779 ;
         wdt:P17 wd:Q408 ;
         rdfs:label ?label .
  FILTER(CONTAINS(LCASE(?label), "disability sport media"))
  FILTER(LANG(?label) = "en")
}

SELECT ?sub WHERE {
  wd:Q48816778 wdt:P361 ?sub .
  OPTIONAL { ?sub rdfs:label ?label . FILTER(LANG(?label) = "en") }
  FILTER(CONTAINS(LCASE(?label), "disability"))
}

SELECT ?award ?label WHERE {
  ?award wdt:P361 wd:Q48816778 ;
         rdfs:label ?label .
  FILTER(CONTAINS(LCASE(?label), "disability") || CONTAINS(LCASE(?label), "para"))
  FILTER(LANG(?label) = "en")
}

SELECT ?awardLabel WHERE {
  wd:Q7579596 rdfs:label ?awardLabel .
  FILTER(LANG(?awardLabel) = 'en')
} LIMIT 1
